itle_typography_font_size":{"unit":"px","size":24,"sizes":[]},"link_click":"box","__dynamic__":{"link":"[elementor-tag id="8d0e42d" name="internal-url" settings="%7B%22type%22%3A%22post%22%2C%22post_id%22%3A%222470%22%7D"]"}},"elements":[],"widgetType":"call-to-action"}],"isInner":true}],"isInner":true}],"isInner":false}],"isInner":false},{"id":"22e5b6e","elType":"section","settings":{"stretch_section":"section-stretched","structure":"30","background_background":"classic","margin":{"unit":"px","top":"80","right":0,"bottom":"0","left":0,"isLinked":false},"padding":{"unit":"px","top":"80","right":"0","bottom":"80","left":"0","isLinked":false},"__globals__":{"background_color":"globals/colors?id=primary"},"padding_mobile":{"unit":"px","top":"40","right":"0","bottom":"40","left":"0","isLinked":false}},"elements":[{"id":"c3c1694","elType":"column","settings":{"_column_size":33,"_inline_size":48.332},"elements":[{"id":"dde5ac6","elType":"widget","settings":{"title":"About the program","title_color":"#FFFFFF","typography_typography":"custom","typography_font_size_mobile":{"unit":"px","size":30,"sizes":[]}},"elements":[],"widgetType":"heading"},{"id":"9ba4d6e","elType":"widget","settings":{"editor":"<p>But in certain circumstances and owing to the claims of duty or the obligations of business it will frequently occur that pleasures have to be repudiated and annoyances accepted.</p>","text_color":"#FFFFFFA1","typography_typography":"custom","typography_font_size":{"unit":"px","size":22,"sizes":[]},"typography_line_height":{"unit":"em","size":1.4,"sizes":[]}},"elements":[],"widgetType":"text-editor"},{"id":"fd227a0","elType":"widget","settings":{"editor":"<p><span style="font-size: 16px; background-color: var( --e-global-color-primary );">But in certain circumstances and owing to the claims of duty or the obligations of business it will frequently occur that pleasures have to be repudiated and annoyances accepted. The wise man therefore always holds in these matters to this principle of selection: he rejects pleasures to secure other greater pleasures, or else he endures pains to avoid worse pains.</span></p>","text_color":"#FFFFFFA1"},"elements":[],"widgetType":"text-editor"},{"id":"b8e2483","elType":"widget","settings":{"icon_list":[{"text":"Fusce ornare lorem nec velit eleifend aliquam.","_id":"3d64dad"},{"text":"Curabitur sodales turpis quis euismod eleifend.","_id":"c02ef48"},{"text":"Vivamus ac elit placerat, porta leo id, ornare dui.","_id":"e6fcae3"}],"space_between":{"unit":"px","size":8,"sizes":[]},"text_color":"#FFFFFF","__globals__":{"icon_color":"globals/colors?id=secondary"}},"elements":[],"widgetType":"icon-list"},{"id":"eaf34f2","elType":"widget","settings":{"editor":"<p>On the other hand, we denounce with righteous indignation and dislike men who are so beguiled and demoralized by the charms of pleasure of the moment, so blinded by desire, that they cannot foresee the pain and trouble that are bound to ensue; and equal blame belongs to those who fail in their duty through weakness.</p>","text_color":"#FFFFFFA1"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"f166609","elType":"column","settings":{"_column_size":33,"_inline_size":3.061,"hide_mobile":"hidden-mobile"},"elements":[],"isInner":false},{"id":"3259c96","elType":"column","settings":{"_column_size":33,"_inline_size":48.244},"elements":[{"id":"717a141","elType":"section","settings":{"content_position":"middle","structure":"20","margin":{"unit":"px","top":"0","right":0,"bottom":"20","left":0,"isLinked":false}},"elements":[{"id":"ab2ece6","elType":"column","settings":{"_column_size":50,"_inline_size":15.273},"elements":[{"id":"25f38af","elType":"widget","settings":{"image":{"url":"https://native-church.imithemes.com/parish/wp-content/uploads/sites/4/2021/08/parish-demo__favicon.png","id":2464,"alt":"","source":"library"},"width_mobile":{"unit":"%","size":16,"sizes":[]}},"elements":[],"widgetType":"image"}],"isInner":true},{"id":"f560fe5","elType":"column","settings":{"_column_size":50,"_inline_size":84.727},"elements":[{"id":"b5bf369","elType":"widget","settings":{"title":"How to apply","header_size":"h3","title_color":"#FFFFFF","align_mobile":"center"},"elements":[],"widgetType":"heading"}],"isInner":true}],"isInner":true},{"id":"3ae91f3","elType":"widget","settings":{"tabs":[{"tab_title":"1. Complete Application Form","tab_content":"<p>Tell us a little about yourself and we’ll help with the rest. Our convenient online application tool only takes 10 minutes to complete.</p>","_id":"4bb27f1"},{"tab_title":"2. Confirmation of Application","tab_content":"<p>Once you have submitted your application, NC will acknowledge receipt of your application by phone or email within two working days.</p>","_id":"44e6077"},{"_id":"fc953b6","tab_title":"3. Application Review","tab_content":"<p>NC will review your application to confirm you meet our requirements. If so, you will then be asked to complete an interview as part of the review process.</p>"},{"_id":"3c6d9ec","tab_title":"4. Application Interview","tab_content":"<p>Interviews are usually completed over the phone with a member of the Academic Team. The purpose of the interview is to get to know you better, hear about your future plans, understand why you are interested in the course, any particular papers you like and your understanding of the internship program.</p>"},{"_id":"48e40cd","tab_title":"5. Fee Payment","tab_content":"<p>NC will issued an invoice for the balance of your first year tuition fees, due prior to the commencement date. On payment of this invoice you will be issued with a receipt of payment.</p>"}],"selected_icon":{"value":"","library":""},"faq_schema":"yes","title_background":"#FFFFFF","tab_active_color":"#AC1E30","title_padding":{"unit":"px","top":"22","right":"22","bottom":"22","left":"22","isLinked":true},"content_background_color":"#FFFFFF","__globals__":{"title_background":"","border_color":"","tab_active_color":"globals/colors?id=primary